import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule, NgIf, NgFor } from '@angular/common';
import { AdminService } from '../../../core/services/admin.service';

@Component({
  selector: 'app-manage-jobs',
  standalone: true,
  imports: [CommonModule, NgIf, NgFor],
  templateUrl: './manage-jobs.component.html',
  styleUrls: ['./manage-jobs.component.css']
})
export class ManageJobsComponent implements OnInit {
  private adminService = inject(AdminService);
  private cdr = inject(ChangeDetectorRef);

  jobsList: any[] = [];
  isLoading = false;

  ngOnInit(): void {
    this.isLoading = true;
    this.adminService.getAllJobs().subscribe({
      next: (data) => {
        this.jobsList = data;
        this.isLoading = false;
        this.cdr.detectChanges();
      },
      error: () => this.isLoading = false
    });
  }

  onDeleteJob(jobId: number): void {
    if (confirm("❌ Voulez-vous vraiment retirer cette offre d'emploi de Tun-Job ?")) {
      this.adminService.deleteJob(jobId).subscribe({
        next: () => {
          this.jobsList = this.jobsList.filter(j => j.id !== jobId);
          this.cdr.detectChanges();
        }
      });
    }
  }
}
<div class="manage-container">
  <div class="card-header-flex">
    <div class="card-header-left">
      <h3><i class="bi bi-briefcase-fill"></i> Modération des Offres</h3>
      <p>Consultez l'ensemble des offres d'emploi actives et supprimez les annonces non conformes.</p>
    </div>
  </div>

  <div class="manage-card-premium">
    <div class="table-wrapper-premium">
      
      <div *ngIf="isLoading" class="loading-box">
        <i class="bi bi-arrow-clockwise spinning"></i> Chargement des offres d'emploi...
      </div>

      <table *ngIf="!isLoading" class="jobs-table-premium">
        <thead>
          <tr>
            <th class="th-left-padding">Titre du poste / Recruteur</th>
            <th>Localisation</th>
            <th>Type de Contrat</th>
            <th class="th-center-align">Actions</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let job of jobsList" class="table-row-premium">
            <td class="job-company-cell">
              <span class="clickable-job-title" style="font-size: 14px !important; font-weight: 700;">{{ job.title }}</span>
              <span class="company-sub-badge"><i class="bi bi-building"></i> {{ job.company_name || 'Recruteur' }}</span>
            </td>
            <td class="date-text-cell-premium">
              <div class="date-container-premium">
                <i class="bi bi-geo-alt"></i>
                <span>{{ job.location }}</span>
              </div>
            </td>
            <td class="date-text-cell-premium">
              <div class="date-container-premium">
                <i class="bi bi-file-earmark-text"></i>
                <span>{{ job.contract_type }}</span>
              </div>
            </td>
            <td class="status-cell-premium">
              <button class="btn-action-delete" (click)="onDeleteJob(job.id)">
                <i class="bi bi-x-circle-fill"></i> Retirer
              </button>
            </td>
          </tr>
        </tbody>
      </table>

    </div>
  </div>
</div>
